f5_irule:
when HTTP_REQUEST {
    set lower_uri [string tolower [HTTP::uri]]
    set query [string tolower [HTTP::query]]
    if {[regexp {(union[[:space:]]+select|insert[[:space:]]+into|drop[[:space:]]+table|'[[:space:]]+or[[:space:]]+1=1|--|/\*)} $query]} {
        log local0. "WAF SQLi baseline matched for [IP::client_addr] on $lower_uri"
        HTTP::respond 403 content "Request blocked by security policy"
        event disable all
    }
  }
